<div class="grid grid-2"><div class="card"><h3>Salary Component</h3><form method="post" action="<?=url('/payroll/component')?>"><?=csrf_field()?><label>Code</label><input name="code" required><label>Name</label><input name="name" required><label>Type</label><select name="type"><option value="earning">Earning</option><option value="deduction">Deduction</option><option value="company_contribution">Company Contribution</option></select><label>Calculation</label><select name="calculation_type"><option>fixed</option><option>formula</option><option>manual</option></select><label>Default Amount</label><input name="default_amount" type="number" step="0.01" value="0"><label><input type="checkbox" name="taxable" checked style="width:auto"> Taxable</label><button class="btn btn-primary">Save Component</button></form></div><div class="card"><h3>Assign Salary</h3><form method="post" action="<?=url('/payroll/assign-salary')?>"><?=csrf_field()?><label>Employee</label><select name="employee_id"><?php foreach($employees as $e1):?><option value="<?=e($e1['id'])?>"><?=e($e1['full_name'])?></option><?php endforeach;?></select><label>Component</label><select name="component_id"><?php foreach($components as $c):?><option value="<?=e($c['id'])?>"><?=e($c['code'].' - '.$c['name'])?></option><?php endforeach;?></select><label>Amount</label><input name="amount" type="number" step="0.01" required><label>Effective Date</label><input name="effective_date" type="date" required><button class="btn btn-primary">Assign</button></form></div></div><br><div class="card"><h3>Components</h3><table class="table"><tr><th>Code</th><th>Name</th><th>Type</th><th>Default</th></tr><?php foreach($components as $c):?><tr><td><?=e($c['code'])?></td><td><?=e($c['name'])?></td><td><?=e($c['type'])?></td><td><?=money_id($c['default_amount'])?></td></tr><?php endforeach;?></table></div>
